import{_ as r,o,c as l,ag as i}from"./chunks/framework.BbyMWZAR.js";const c=JSON.parse('{"title":"常见算法解题范式速览","description":"","frontmatter":{"title":"常见算法解题范式速览","difficulty":"medium","tags":["双指针","滑动窗口","二分","BFS","DFS","DP","贪心","回溯","并查集"],"estimate":25},"headers":[],"relativePath":"domains/algorithms/qa/qa-04-problem-solving-paradigms.md","filePath":"domains/algorithms/qa/qa-04-problem-solving-paradigms.md","lastUpdated":1783504823000}'),a={name:"domains/algorithms/qa/qa-04-problem-solving-paradigms.md"};function n(s,t,e,d,g,h){return o(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="问答-04-进阶-常见算法解题范式速览" tabindex="-1">问答 04（进阶）：常见算法解题范式速览 <a class="header-anchor" href="#问答-04-进阶-常见算法解题范式速览" aria-label="Permalink to &quot;问答 04（进阶）：常见算法解题范式速览&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>面试和刷题时，识别「这道题该用什么套路」是重要能力。请梳理常见的解题范式（双指针、滑动窗口、二分、BFS、DFS、DP、贪心、回溯、并查集），说明它们各自的适用信号、模板、易错点。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><h3 id="_1-双指针-two-pointers" tabindex="-1">1. 双指针（Two Pointers） <a class="header-anchor" href="#_1-双指针-two-pointers" aria-label="Permalink to &quot;1. 双指针（Two Pointers）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：数组/字符串<strong>有序</strong>或题目允许排序；寻找一对/若干个元素满足某种关系。</li><li><strong>两种模式</strong>： <ul><li>对撞指针：左右两端向中间靠拢。经典题：两数之和（有序数组）、盛最多水的容器。</li><li>快慢指针：同一端出发，速度不同。经典题：链表判环、去除有序数组重复项、找中点。</li></ul></li><li><strong>易错</strong>：忘记去重导致答案重复（如三数之和）；边界条件 <code>&lt;</code> 还是 <code>&lt;=</code>。</li></ul><h3 id="_2-滑动窗口-sliding-window" tabindex="-1">2. 滑动窗口（Sliding Window） <a class="header-anchor" href="#_2-滑动窗口-sliding-window" aria-label="Permalink to &quot;2. 滑动窗口（Sliding Window）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：连续子数组/子串上求最长/最短/计数/极值。</li><li><strong>模板</strong>：右指针扩张，直到不满足条件，再收缩左指针。</li><li><strong>经典题</strong>：最长不重复子串、最小覆盖子串、长度最小的子数组。</li><li><strong>易错</strong>：窗口内计数用 Map 时，收缩时忘记减 1；忘记更新答案的时机（每次收缩后还是每次扩张后）。</li></ul><h3 id="_3-二分查找-binary-search" tabindex="-1">3. 二分查找（Binary Search） <a class="header-anchor" href="#_3-二分查找-binary-search" aria-label="Permalink to &quot;3. 二分查找（Binary Search）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：搜索空间<strong>单调</strong>（数组有序、答案对参数单调），求「大于等于 x 的第一个」「小于等于 x 的最后一个」等。</li><li><strong>两种范式</strong>： <ul><li>在数组里找值。</li><li><strong>二分答案</strong>：答案有单调性时，直接对答案区间二分（如「分割数组的最大值最小化」）。</li></ul></li><li><strong>易错</strong>：<code>while (l &lt;= r)</code> 与 <code>while (l &lt; r)</code> 的循环不变量不同；<code>mid = l + (r - l) / 2</code> 防溢出（JS 不严重但保持习惯）；找左/右边界时更新 <code>l = mid + 1</code> 或 <code>r = mid</code>。</li></ul><h3 id="_4-bfs-广度优先搜索" tabindex="-1">4. BFS（广度优先搜索） <a class="header-anchor" href="#_4-bfs-广度优先搜索" aria-label="Permalink to &quot;4. BFS（广度优先搜索）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：<strong>最短路径 / 最少步骤 / 层序遍历</strong>；边权全部相等的图。</li><li><strong>数据结构</strong>：队列 + visited 集合。</li><li><strong>经典题</strong>：二叉树层序、最短路径、迷宫最少步数、单词接龙。</li><li><strong>易错</strong>：忘记在入队时立刻标记 visited（放行时才标记会导致同一节点入队多次）。</li></ul><h3 id="_5-dfs-深度优先搜索" tabindex="-1">5. DFS（深度优先搜索） <a class="header-anchor" href="#_5-dfs-深度优先搜索" aria-label="Permalink to &quot;5. DFS（深度优先搜索）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：遍历/搜索一棵树或一张图的所有分支；判断连通性；生成所有方案（也常和回溯结合）。</li><li><strong>实现</strong>：递归或显式栈。</li><li><strong>经典题</strong>：岛屿数量、二叉树各种遍历、连通分量、拓扑排序（后序 + 逆序）。</li><li><strong>易错</strong>：图上 DFS 忘记标记 visited 导致死循环；递归爆栈时改成迭代。</li></ul><h3 id="_6-动态规划-dp" tabindex="-1">6. 动态规划（DP） <a class="header-anchor" href="#_6-动态规划-dp" aria-label="Permalink to &quot;6. 动态规划（DP）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：最优子结构 + 重叠子问题。求最优值、方案数、可行性。</li><li><strong>步骤</strong>：定义状态 → 转移方程 → 初始化 → 遍历顺序 → 优化空间。</li><li><strong>经典类型</strong>：线性 DP、区间 DP、背包、树形 DP、状压 DP、数位 DP、概率/期望 DP。</li><li><strong>易错</strong>：状态定义不完整；转移方程漏了某个来源；遍历顺序与依赖不符。</li></ul><h3 id="_7-贪心-greedy" tabindex="-1">7. 贪心（Greedy） <a class="header-anchor" href="#_7-贪心-greedy" aria-label="Permalink to &quot;7. 贪心（Greedy）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：每一步都能做出<strong>局部最优选择</strong>，且能证明局部最优可以推出全局最优。</li><li><strong>经典题</strong>：跳跃游戏、区间调度、分发糖果、最小生成树（Prim/Kruskal）、Dijkstra。</li><li><strong>易错</strong>：无法证明贪心策略正确；容易与 DP 混淆——<strong>举反例</strong>验证贪心。</li></ul><h3 id="_8-回溯-backtracking" tabindex="-1">8. 回溯（Backtracking） <a class="header-anchor" href="#_8-回溯-backtracking" aria-label="Permalink to &quot;8. 回溯（Backtracking）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：需要枚举<strong>所有解 / 满足条件的解</strong>：排列组合、子集、划分、N 皇后、数独。</li><li><strong>模板</strong>：选 → 递归 → 撤销（restore state）。</li><li><strong>优化</strong>：剪枝、排序后跳过重复。</li><li><strong>易错</strong>：进入下一层前要把当前选择加入路径，返回时要<strong>撤销</strong>；重复元素去重（<code>i &gt; start &amp;&amp; nums[i] === nums[i-1]</code>）。</li></ul><h3 id="_9-并查集-union-find-dsu" tabindex="-1">9. 并查集（Union-Find / DSU） <a class="header-anchor" href="#_9-并查集-union-find-dsu" aria-label="Permalink to &quot;9. 并查集（Union-Find / DSU）&quot;">​</a></h3><ul><li><strong>适用信号</strong>：<strong>动态</strong>判断集合归属、连通性；元素分组；离线处理连通问题。</li><li><strong>优化</strong>：路径压缩 + 按秩合并，均摊近 O(1)（阿克曼函数反函数 α(n)）。</li><li><strong>经典题</strong>：朋友圈、账号合并、冗余连接、检测二分图（配合扩展域并查集）。</li><li><strong>易错</strong>：初始化 parent 每个人指向自己；忘了压缩路径；秩不更新。</li></ul><p><strong>范式识别 cheat sheet</strong></p><table tabindex="0"><thead><tr><th>关键词</th><th>优先考虑</th></tr></thead><tbody><tr><td>有序数组、一对/多个元素、平方复杂度嫌慢</td><td>双指针</td></tr><tr><td>连续子串/子数组、极值</td><td>滑动窗口</td></tr><tr><td>有序、找位置、答案有单调性</td><td>二分查找 / 二分答案</td></tr><tr><td>最短、最少步数、层次</td><td>BFS</td></tr><tr><td>所有路径、连通块、后序处理</td><td>DFS</td></tr><tr><td>最优值/计数/可行、含重叠子问题</td><td>DP</td></tr><tr><td>局部最优可推全局</td><td>贪心</td></tr><tr><td>全排列、组合、子集、划分方案</td><td>回溯</td></tr><tr><td>连通性、动态合并集合</td><td>并查集</td></tr><tr><td>图上最短路（正权/非负权）</td><td>Dijkstra</td></tr><tr><td>图上最短路（有负权，无负环）</td><td>Bellman-Ford / SPFA</td></tr><tr><td>稀疏图最短路（0-1 权）</td><td>0-1 BFS</td></tr></tbody></table><h2 id="追问-1-滑动窗口和双指针有什么区别-为什么滑动窗口本质上也是双指针" tabindex="-1">追问 1：滑动窗口和双指针有什么区别？为什么滑动窗口本质上也是双指针？ <a class="header-anchor" href="#追问-1-滑动窗口和双指针有什么区别-为什么滑动窗口本质上也是双指针" aria-label="Permalink to &quot;追问 1：滑动窗口和双指针有什么区别？为什么滑动窗口本质上也是双指针？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>双指针</strong>是更宽泛的概念，任何用两个索引扫数组/字符串的技巧都可以叫双指针，包括对撞、快慢、同向。</li><li><strong>滑动窗口</strong>是双指针的一个具体子类——<strong>两个同向指针</strong>围成一个区间（窗口），根据条件动态伸缩。</li><li>区别在于问题结构：<strong>滑动窗口的答案总是「一个连续区间」的性质（最长/最短/计数）</strong>，而普通双指针可能是「找一对具体元素」。</li><li>二者的区分不重要，写题时只要能清晰描述指针的移动规则即可。</li></ul><h2 id="追问-2-bfs-和-dfs-谁更适合找最短路径-为什么-如果是加权图呢" tabindex="-1">追问 2：BFS 和 DFS 谁更适合找最短路径？为什么？如果是加权图呢？ <a class="header-anchor" href="#追问-2-bfs-和-dfs-谁更适合找最短路径-为什么-如果是加权图呢" aria-label="Permalink to &quot;追问 2：BFS 和 DFS 谁更适合找最短路径？为什么？如果是加权图呢？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>边权都相等（比如都是 1）的无向图</strong>：BFS 天然找到最短路径。因为 BFS 按距离一层层扩展，第一次访问到目标节点时经过的边数一定最少。</li><li><strong>DFS 也能找</strong>，但需要遍历所有路径取最短，效率差得多，且实现复杂。</li><li><strong>加权图</strong>：普通 BFS 不再正确，需要： <ul><li>非负权：<strong>Dijkstra</strong>（BFS + 优先队列）。</li><li>有负权、无负环：<strong>Bellman-Ford / SPFA</strong>。</li><li>权只有 0 和 1：<strong>0-1 BFS</strong>（双端队列，0 权前插、1 权后插）。</li><li>所有点对最短路径：<strong>Floyd-Warshall</strong>（O(n³)）。</li></ul></li></ul><h2 id="追问-3-贪心和-dp-都能求最优解-如何选择-举一个反例说明贪心是错的" tabindex="-1">追问 3：贪心和 DP 都能求最优解，如何选择？举一个反例说明贪心是错的？ <a class="header-anchor" href="#追问-3-贪心和-dp-都能求最优解-如何选择-举一个反例说明贪心是错的" aria-label="Permalink to &quot;追问 3：贪心和 DP 都能求最优解，如何选择？举一个反例说明贪心是错的？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>优先尝试贪心</strong>（更简单、更快），如果<strong>能构造反例</strong>证明贪心不对，再退化到 DP。</li><li>判断标准：<strong>局部最优是否等价于全局最优</strong>（可用交换论证、归纳法证明）。</li><li>经典反例——<strong>0-1 背包</strong>：<code>容量 W=10</code>，物品 <code>(重, 价) = (5, 40), (4, 30), (6, 50)</code>。 <ul><li>贪心「单位价值最高优先」：先选 (5, 40)（8/kg），再选 (4, 30)，剩 1 装不下 (6, 50)，总价 70。</li><li>最优解：选 (4, 30) + (6, 50) = 总价 80。</li><li>贪心失败的原因是物品不可拆分，「当前最好」牺牲了后续的更好组合。</li></ul></li><li>若允许拆分（分数背包），贪心「单位价值最高」就对了——这就是<strong>问题结构</strong>决定策略是否成立。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/algorithms/RESOURCES">算法 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://oi-wiki.org/" target="_blank" rel="noreferrer">OI Wiki</a>：双指针、二分、BFS/DFS、DP、贪心、回溯等范式的分类与模板</li><li><a href="https://leetcode.com/problemset/" target="_blank" rel="noreferrer">LeetCode Problemset</a>：按标签刷题，验证范式识别与模板熟练度</li><li><a href="https://visualgo.net/en" target="_blank" rel="noreferrer">VisuAlgo</a>：BFS/DFS、二分、并查集等算法的交互式演示</li></ul>',36)])])}const b=r(a,[["render",n]]);export{c as __pageData,b as default};
